import React from 'react';
import Dialog from './Dialog/Dialog';
import Mass from './Mass/Mass';
import s from './NavMassage.module.css'

const NavMassage = () => {

    let dialogs = [
        { id: 1, name: "Misha" },
        { id: 2, name: "Vika Nine 22" },
        { id: 3, name: "Sinfozatron" },
        { id: 4, name: "Dasha Nine 2" }
    ]

    let messages = [
        { id: 1, message: "Привет" },
        { id: 2, message: "Игорек,как дела?" },
        { id: 3, message: "В качалку гоним к 12.00" },
        { id: 4, message: "Молчишь-в жопе торчишь" }
    ]

    let dialogsElement =
        dialogs.map(d => <Dialog name={d.name} id={d.id} />);

    let messagesElement =
        messages.map(m => <Mass message={m.message} />);
    return (
        <div className={s.navmassage} >
            <div className={s.dialog}>
                {dialogsElement}
            </div>
            <div>
                {messagesElement}
            </div>
        </div>
    )
}
export default NavMassage;
